CREATE OR REPLACE VIEW csweb_reports.vw_f1_by_region AS
SELECT COALESCE(NULLIF(fc.region_name,''),'(unknown)') AS label, COUNT(*) AS cases
FROM `csweb_f1_breakout`.`level-1` l JOIN `csweb_f1_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f1_breakout`.field_control fc ON fc.`level-1-id`=l.`level-1-id`
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f1_by_province AS
SELECT COALESCE(NULLIF(fc.province_name,''),'(unknown)') AS label, COUNT(*) AS cases
FROM `csweb_f1_breakout`.`level-1` l JOIN `csweb_f1_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f1_breakout`.field_control fc ON fc.`level-1-id`=l.`level-1-id`
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f1_by_city AS
SELECT COALESCE(NULLIF(fc.city_name,''),'(unknown)') AS label, COUNT(*) AS cases
FROM `csweb_f1_breakout`.`level-1` l JOIN `csweb_f1_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f1_breakout`.field_control fc ON fc.`level-1-id`=l.`level-1-id`
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f1_by_facility AS
SELECT COALESCE(fn.name, CONCAT('(code ', x.code9, ')')) AS label, COUNT(*) AS cases
FROM (SELECT l.`level-1-id` lid, CONCAT(LPAD(fc.region_code,2,'0'),LPAD(fc.province_huc_code,2,'0'),LPAD(fc.city_municipality_code,3,'0'),LPAD(fc.facility_no,2,'0')) AS code9
      FROM `csweb_f1_breakout`.`level-1` l JOIN `csweb_f1_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f1_breakout`.field_control fc ON fc.`level-1-id`=l.`level-1-id`) x
LEFT JOIN csweb_reports.facility_names fn ON fn.code9=x.code9
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f1_by_ownership AS
SELECT CASE t.q7_ownership WHEN '1' THEN 'Public' WHEN '2' THEN 'Private' ELSE COALESCE(NULLIF(t.q7_ownership,''),'(blank)') END AS label, COUNT(*) AS cases
FROM `csweb_f1_breakout`.`level-1` l JOIN `csweb_f1_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f1_breakout`.b_facility_profile t ON t.`level-1-id`=l.`level-1-id`
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f1_by_service_level AS
SELECT CASE t.q8_service_level WHEN '1' THEN 'Primary Care Facility' WHEN '2' THEN 'Level 1 Hospital' WHEN '3' THEN 'Level 2 Hospital' WHEN '4' THEN 'Level 3 Hospital' ELSE COALESCE(NULLIF(t.q8_service_level,''),'(blank)') END AS label, COUNT(*) AS cases
FROM `csweb_f1_breakout`.`level-1` l JOIN `csweb_f1_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f1_breakout`.b_facility_profile t ON t.`level-1-id`=l.`level-1-id`
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f1_by_result AS
SELECT CASE t.enum_result_first_visit WHEN '1' THEN 'Completed' WHEN '2' THEN 'Postponed' WHEN '3' THEN 'Refused' WHEN '4' THEN 'Incomplete' ELSE COALESCE(NULLIF(t.enum_result_first_visit,''),'(blank)') END AS label, COUNT(*) AS cases
FROM `csweb_f1_breakout`.`level-1` l JOIN `csweb_f1_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f1_breakout`.field_control t ON t.`level-1-id`=l.`level-1-id`
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f3_by_region AS
SELECT COALESCE(NULLIF(fc.region_name,''),'(unknown)') AS label, COUNT(*) AS cases
FROM `csweb_f3_breakout`.`level-1` l JOIN `csweb_f3_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f3_breakout`.field_control fc ON fc.`level-1-id`=l.`level-1-id`
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f3_by_patient_type AS
SELECT CASE t.patient_type WHEN '1' THEN 'Outpatient' WHEN '2' THEN 'Inpatient' ELSE COALESCE(NULLIF(t.patient_type,''),'(blank)') END AS label, COUNT(*) AS cases
FROM `csweb_f3_breakout`.`level-1` l JOIN `csweb_f3_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f3_breakout`.field_control t ON t.`level-1-id`=l.`level-1-id`
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f3_by_sex AS
SELECT CASE t.q7_sex WHEN '1' THEN 'Male' WHEN '2' THEN 'Female' ELSE COALESCE(NULLIF(t.q7_sex,''),'(blank)') END AS label, COUNT(*) AS cases
FROM `csweb_f3_breakout`.`level-1` l JOIN `csweb_f3_breakout`.cases c ON c.id=l.`case-id` AND c.deleted=0 LEFT JOIN `csweb_f3_breakout`.b_patient_profile t ON t.`level-1-id`=l.`level-1-id`
GROUP BY label ORDER BY cases DESC;

CREATE OR REPLACE VIEW csweb_reports.vw_f4_by_region AS
